{
  "summary": "This paper formalizes the problem of Continual Knowledge Learning (CKL) to update large language models' internal knowledge through continual pretraining on new corpora. It introduces benchmark datasets and a novel metric (FUAR) to evaluate knowledge retention, update, and acquisition, and empirically compares several continual learning methods, highlighting the strengths of parameter-expansion approaches.",
  "strengths": [
    {
      "point": "Novel problem formulation addressing continual knowledge updating in LMs",
      "evidence": "Introduces CKL as a distinct continual learning problem focused on renewing internal world knowledge rather than task-specific adaptation."
    },
    {
      "point": "Comprehensive benchmark datasets and evaluation metric",
      "evidence": "Constructs INVARIANT, UPDATED, and NEW LAMA datasets and proposes the FUAR metric to quantify the trade-off between forgetting and knowledge gain."
    },
    {
      "point": "Empirical evaluation of multiple baseline methods",
      "evidence": "Adapts and compares regularization, rehearsal, and parameter-expansion methods, showing parameter-expansion methods outperform others in CKL."
    },
    {
      "point": "Insights into challenges unique to CKL",
      "evidence": "Analyzes effects of multi-phase continual pretraining, data exposure frequency, and transferability across LM architectures."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient positioning relative to recent knowledge editing and retrieval-augmented methods",
      "evidence": "Related Work lacks thorough discussion or comparison with recent knowledge injection or dynamic knowledge integration approaches."
    },
    {
      "point": "Limited justification and representativeness of dataset choices",
      "evidence": "Selection criteria for news corpus and LAMA subsets are briefly described without detailed rationale or discussion of real-world knowledge shift representativeness."
    },
    {
      "point": "Assumption that INVARIANT knowledge is truly time-invariant without error analysis",
      "evidence": "No discussion on potential evolution or noise in supposedly stable facts, which could bias forgetting evaluation."
    },
    {
      "point": "Lack of clarity and completeness in implementation and reproducibility details",
      "evidence": "Missing exact training schedules, hyperparameter tuning protocols, hardware specs, and annotation guidelines for dataset creation."
    },
    {
      "point": "FUAR metric may obscure nuanced trade-offs and lacks formal definition",
      "evidence": "Aggregates forgetting and knowledge gain into a single ratio without complementary metrics or illustrative examples."
    },
    {
      "point": "Scalability challenges of parameter-expansion methods not experimentally addressed",
      "evidence": "Memory growth with multi-phase updates is noted but no pruning or parameter sharing solutions are explored."
    },
    {
      "point": "Limited evaluation beyond news domain and English-centric models",
      "evidence": "No experiments on other domains, modalities, or multilingual and very large-scale LMs."
    },
    {
      "point": "Downstream task evaluation is brief and lacks deep analysis",
      "evidence": "Unclear how CKL improvements generalize across diverse tasks or whether gains stem from updated knowledge."
    },
    {
      "point": "No systematic ablation on data exposure frequency or sampling strategies",
      "evidence": "Observations on repeated data exposure effects are not quantified or explored in detail."
    },
    {
      "point": "Handling of noisy or conflicting knowledge updates is not discussed",
      "evidence": "Potential contradictions between old and new corpora and their impact on CKL are unaddressed."
    }
  ],
  "questions": [
    {
      "question": "How does CKL compare quantitatively and qualitatively with recent knowledge editing or retrieval-augmented methods?",
      "motivation": "Clarifying this would position CKL's novelty and practical advantages more clearly."
    },
    {
      "question": "Can the FUAR metric be decomposed or complemented with additional metrics to better capture trade-offs between forgetting and knowledge gain?",
      "motivation": "This would improve interpretability and guide method development."
    },
    {
      "question": "What strategies can mitigate the scalability issues of parameter-expansion methods in multi-phase continual pretraining?",
      "motivation": "Addressing this is critical for practical deployment of CKL in real-world evolving knowledge scenarios."
    },
    {
      "question": "How robust are the benchmark datasets and annotations, and will the released resources include detailed guidelines and quality control measures?",
      "motivation": "Ensuring dataset reliability is essential for reproducibility and future research."
    },
    {
      "question": "How does CKL perform on non-news domains, multilingual models, and very large-scale LMs?",
      "motivation": "This affects the generalizability and broader applicability of the proposed framework."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
